import { PageTitle } from '../components/PageTitle';

interface Position {
  title: string;
  count: number;
  members: Array<{
    name: string;
    image: string;
    year?: string;
    college?: string;
    major?: string;
    minor?: string;
    pronouns?: string;
    favoriteSnack?: string;
    funFact?: string;
  }>;
}

const executiveBoard: Position[] = [
  { title: 'Co-President', count: 2, members: [] },
  { title: 'Co-Intercollegiate Council', count: 2, members: [] },
  { title: 'Internal Vice President', count: 1, members: [] },
  { title: 'Secretary', count: 1, members: [] },
  { title: 'Treasurer', count: 1, members: [] },
];

const generalBoard: Position[] = [
  { title: 'Co-Media Director', count: 2, members: [] },
  { title: 'Co-Events Chair', count: 2, members: [] },
  { title: 'VCN Director', count: 1, members: [] },
  { title: 'VCN Executive Producer', count: 1, members: [] },
  { title: 'Anh Chi Em Chair', count: 1, members: [] },
  { title: 'Fundraising Chair', count: 1, members: [] },
  { title: 'Community Relations Chair', count: 1, members: [] },
  { title: 'Culture & Philanthropy Chair', count: 1, members: [] },
  { title: 'Co-Historian', count: 2, members: [] },
];

export function Cabinet() {
  return (
    <div className="max-w-4xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
      <PageTitle title="Cabinet" />
      
      <div className="space-y-12">
        {/* Executive Board Section */}
        <div className="bg-gray-800 shadow rounded-lg p-6">
          <h2 className="text-2xl font-bold text-white mb-8 text-center">Executive Board</h2>
          <div className="space-y-12">
            {executiveBoard.map((position, index) => (
              <div key={index} className="space-y-6">
                <h3 className="text-xl font-bold text-purple-400 text-center">{position.title}</h3>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                  {Array.from({ length: position.count }).map((_, memberIndex) => (
                    <div key={memberIndex} className="bg-gray-700 rounded-lg p-6">
                      <div className="flex flex-col items-center space-y-4">
                        <div className="w-32 h-32 rounded-full bg-gray-600 flex items-center justify-center overflow-hidden">
                          <svg xmlns="http://www.w3.org/2000/svg" className="h-16 w-16 text-gray-400" viewBox="0 0 20 20" fill="currentColor">
                            <path fillRule="evenodd" d="M10 9a3 3 0 100-6 3 3 0 000 6zm-7 9a7 7 0 1114 0H3z" clipRule="evenodd" />
                          </svg>
                        </div>
                        <div className="text-center">
                          <p className="text-lg font-medium text-white">Position Available</p>
                          <p className="text-sm text-gray-400">Click to apply</p>
                        </div>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            ))}
          </div>
        </div>

        {/* General Board Section */}
        <div className="bg-gray-800 shadow rounded-lg p-6">
          <h2 className="text-2xl font-bold text-white mb-8 text-center">General Board</h2>
          <div className="space-y-12">
            {generalBoard.map((position, index) => (
              <div key={index} className="space-y-6">
                <h3 className="text-xl font-bold text-purple-400 text-center">{position.title}</h3>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                  {Array.from({ length: position.count }).map((_, memberIndex) => (
                    <div key={memberIndex} className="bg-gray-700 rounded-lg p-6">
                      <div className="flex flex-col items-center space-y-4">
                        <div className="w-32 h-32 rounded-full bg-gray-600 flex items-center justify-center overflow-hidden">
                          <svg xmlns="http://www.w3.org/2000/svg" className="h-16 w-16 text-gray-400" viewBox="0 0 20 20" fill="currentColor">
                            <path fillRule="evenodd" d="M10 9a3 3 0 100-6 3 3 0 000 6zm-7 9a7 7 0 1114 0H3z" clipRule="evenodd" />
                          </svg>
                        </div>
                        <div className="text-center">
                          <p className="text-lg font-medium text-white">Position Available</p>
                          <p className="text-sm text-gray-400">Click to apply</p>
                        </div>
                      </div>
                    </div>
                  ))}
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>
    </div>
  );
}
